"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconRefresh,
  IconSearch,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Banner,
  Button,
  EmptyState,
  Select,
  SearchInput,
  Separator,
  ToggleGroup,
  ToggleGroupItem,
} from "@gunjo/ui";
import {
  AIRPORTS,
  ARRIVALS,
  DEPARTURES,
  HND,
  LAST_REFRESHED,
  MY_FLIGHT_ID,
  type Direction,
  type Flight,
} from "./data";
import { FlightRow } from "./FlightRow";
import { FlightDetailSheet } from "./FlightDetailSheet";

function matchesQuery(flight: Flight, q: string): boolean {
  if (!q) return true;
  const needle = q.trim().toLowerCase();
  return (
    flight.flightNo.toLowerCase().includes(needle) ||
    flight.airlineLabel.toLowerCase().includes(needle) ||
    flight.origin.code.toLowerCase().includes(needle) ||
    flight.destination.code.toLowerCase().includes(needle) ||
    flight.origin.name.includes(needle) ||
    flight.destination.name.includes(needle)
  );
}

export default function FlightStatusPage() {
  const [airport, setAirport] = React.useState(HND.code);
  const [direction, setDirection] = React.useState<Direction>("departure");
  const [query, setQuery] = React.useState("");
  const [selected, setSelected] = React.useState<Flight | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);

  const baseList = direction === "departure" ? DEPARTURES : ARRIVALS;
  const visible = baseList.filter((f) => matchesQuery(f, query));

  // マイフライトは追跡対象が今の方向・空港の一覧にいるときだけピン留め
  const myFlight =
    direction === "departure"
      ? DEPARTURES.find((f) => f.id === MY_FLIGHT_ID) ?? null
      : null;
  const myFlightVisible = myFlight && matchesQuery(myFlight, query);

  const listWithoutMine = visible.filter((f) => f.id !== MY_FLIGHT_ID);

  // 乱れ（遅延・欠航）の件数を運航のお知らせに使う
  const disrupted = baseList.filter(
    (f) => f.status === "delayed" || f.status === "cancelled"
  );

  const openFlight = (flight: Flight) => {
    setSelected(flight);
    setSheetOpen(true);
  };

  const directionLabel = direction === "departure" ? "出発便" : "到着便";

  return (
    <main className="mx-auto flex min-h-screen w-full max-w-md flex-col bg-background pb-12">
      {/* ヘッダー */}
      <header className="sticky top-0 z-10 border-b border-border bg-background/95 px-4 pb-3 pt-4 backdrop-blur">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-lg font-bold tracking-tight">運航状況案内</h1>
            <p className="text-xs text-muted-foreground">
              国内線 · {LAST_REFRESHED} 時点
            </p>
          </div>
          <Button
            variant="ghost"
            size="sm"
            className="gap-1.5 text-muted-foreground"
            aria-label="最新の運航状況に更新"
          >
            <IconRefresh className="h-4 w-4" aria-hidden />
            更新
          </Button>
        </div>

        {/* 空港・方向の選択 */}
        <div className="mt-3 space-y-2.5">
          <Select
            value={airport}
            onChange={(e) => setAirport(e.target.value)}
            aria-label="空港を選択"
          >
            {AIRPORTS.map((a) => (
              <option key={a.code} value={a.code}>
                {a.name}（{a.code}）
              </option>
            ))}
          </Select>

          <ToggleGroup
            type="single"
            value={direction}
            onValueChange={(v) => {
              if (v === "departure" || v === "arrival") setDirection(v);
            }}
            disallowEmpty
            variant="outline"
            className="grid w-full grid-cols-2 gap-2"
            aria-label="出発便・到着便の切替"
          >
            <ToggleGroupItem
              value="departure"
              className="h-10 data-[state=on]:bg-foreground data-[state=on]:text-background"
            >
              出発便
            </ToggleGroupItem>
            <ToggleGroupItem
              value="arrival"
              className="h-10 data-[state=on]:bg-foreground data-[state=on]:text-background"
            >
              到着便
            </ToggleGroupItem>
          </ToggleGroup>

          <SearchInput
            value={query}
            onValueChange={setQuery}
            placeholder="便名・区間で検索（例：NH015 / 札幌）"
            aria-label="便名または区間で検索"
          />
        </div>
      </header>

      <div className="flex-1 px-4 pt-3">
        {/* 運航のお知らせ / アラート */}
        {disrupted.length > 0 ? (
          <Banner
            variant="warning"
            icon={<IconAlertTriangle className="h-4 w-4" aria-hidden />}
            className="mb-3 rounded-lg"
          >
            {airport === HND.code ? "羽田" : airport}発着の{directionLabel}で
            {disrupted.length}件の遅延・欠航があります
          </Banner>
        ) : null}

        {/* マイフライト（追跡中の便をトップに固定） */}
        {myFlight && myFlightVisible ? (
          <section aria-labelledby="myflight-heading" className="mb-4">
            <h2
              id="myflight-heading"
              className="mb-1.5 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
            >
              マイフライト
            </h2>
            <FlightRow
              flight={myFlight}
              direction={direction}
              pinned
              selected={selected?.id === myFlight.id && sheetOpen}
              onSelect={openFlight}
            />
            <Separator className="mt-4" />
          </section>
        ) : null}

        {/* 便一覧 */}
        <section aria-labelledby="list-heading">
          <div className="mb-1.5 flex items-baseline justify-between">
            <h2
              id="list-heading"
              className="text-xs font-semibold uppercase tracking-wide text-muted-foreground"
            >
              {directionLabel}一覧
            </h2>
            <span className="text-xs text-muted-foreground">
              {listWithoutMine.length}便
            </span>
          </div>

          {listWithoutMine.length === 0 ? (
            <EmptyState
              icon={<IconSearch className="h-6 w-6" aria-hidden />}
              title="該当する便がありません"
              description={
                query
                  ? `「${query}」に一致する便は見つかりませんでした。便名や区間を確認してください。`
                  : "この時間帯に表示できる便がありません。"
              }
              action={
                query ? (
                  <Button variant="outline" size="sm" onClick={() => setQuery("")}>
                    検索条件をクリア
                  </Button>
                ) : undefined
              }
            />
          ) : (
            <ul className="space-y-2.5" aria-label={`${directionLabel}の一覧`}>
              {listWithoutMine.map((flight) => (
                <li key={flight.id}>
                  <FlightRow
                    flight={flight}
                    direction={direction}
                    selected={selected?.id === flight.id && sheetOpen}
                    onSelect={openFlight}
                  />
                </li>
              ))}
            </ul>
          )}
        </section>

        {/* 凡例的な注意書き */}
        <Alert className="mt-5">
          <AlertTitle className="text-sm">時刻について</AlertTitle>
          <AlertDescription className="text-xs">
            時刻は定刻（STD/STA）を表示しています。
            <span className="text-warning">橙色</span>
            の時刻は変更後の出発・到着見込です。状況は随時更新されます。
          </AlertDescription>
        </Alert>
      </div>

      <FlightDetailSheet
        flight={selected}
        direction={direction}
        open={sheetOpen}
        onOpenChange={setSheetOpen}
      />
    </main>
  );
}

// 国内線フライト運航状況案内 — sample data layer.
