  flightNo: string;
  /** 航空会社名 */
  airline: "ANA" | "JAL" | "SKY" | "ADO";
  airlineLabel: string;
  origin: Airport;
  destination: Airport;
  /** 定刻 STD (出発便) / STA (到着便) "HH:MM" */
  scheduled: string;
  /** 変更後の時刻 / 出発・到着見込 "HH:MM"。遅延・欠航時のみ。 */
  estimated?: string;
  status: FlightStatus;
  /** 遅延の理由 */
  delayReason?: string;
  /** 搭乗口（ゲート）番号 */
  gate?: string;
  /** 搭乗口が変更されたか */
  gateChanged?: boolean;
  /** スポット番号（到着便） */
  spot?: string;
  /** ターミナル */
  terminal: string;
  /** 機材 */
  aircraft: string;
  /** 手荷物受取所（ターンテーブル）番号（到着便） */
  baggageClaim?: string;
}

