"use client";

import * as React from "react";
import { IconAlertTriangle, IconPlane } from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  MetadataList,
  RouteStops,
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  type MetadataListItem,
  type RouteStopItem,
  type RouteStopStatus,
} from "@gunjo/ui";
import type { Direction, Flight } from "./data";
import { STATUS_LABEL } from "./data";
import { StatusBadge } from "./status-ui";

function diffMinutes(scheduled: string, estimated: string): number {
  const [sh, sm] = scheduled.split(":").map(Number);
  const [eh, em] = estimated.split(":").map(Number);
  return eh * 60 + em - (sh * 60 + sm);
}

/** 出発空港 → 到着空港 の区間を RouteStops の2ノードで表現 */
function legStops(flight: Flight): RouteStopItem[] {
  const delayed = flight.status === "delayed" && flight.estimated;
  const delayMinutes = delayed ? diffMinutes(flight.scheduled, flight.estimated!) : undefined;

  const originStatus: RouteStopStatus =
    flight.status === "cancelled"
      ? "failed"
      : flight.status === "departed" || flight.status === "arrived"
        ? "completed"
        : flight.status === "delayed"
          ? "delayed"
          : flight.status === "boarding"
            ? "current"
            : "pending";

  const destStatus: RouteStopStatus =
    flight.status === "arrived"
      ? "completed"
      : flight.status === "cancelled"
        ? "failed"
        : flight.status === "delayed"
          ? "delayed"
          : "pending";

  return [
    {
      id: "origin",
      title: `${flight.origin.name} (${flight.origin.code})`,
      description: "出発",
      status: originStatus,
      plannedTime: flight.scheduled,
      actualTime: delayed ? flight.estimated : undefined,
      delayMinutes,
    },
    {
      id: "destination",
      title: `${flight.destination.name} (${flight.destination.code})`,
      description: "到着",
      status: destStatus,
    },
  ];
}

function detailItems(flight: Flight, direction: Direction): MetadataListItem[] {
  const items: MetadataListItem[] = [
    {
      label: "ターミナル",
      value: flight.terminal,
    },
    {
      label: "機材",
      value: flight.aircraft,
    },
  ];

  if (direction === "departure") {
    items.push({
      label: "搭乗口（ゲート）",
      value: flight.gate ? (
        <span className="inline-flex items-center gap-2">
          <span className="font-semibold tabular-nums">{flight.gate} 番</span>
          {flight.gateChanged ? (
            <Badge variant="warning" className="text-[11px]">
              変更
            </Badge>
          ) : null}
        </span>
      ) : (
        "—"
      ),
    });
  } else {
    items.push({
      label: "到着スポット",
      value: flight.spot ? `${flight.spot} 番` : "—",
    });
    items.push({
      label: "手荷物受取所",
      value: flight.baggageClaim ? `ターンテーブル ${flight.baggageClaim}` : "—",
    });
  }

  return items;
}

export interface FlightDetailSheetProps {
  flight: Flight | null;
  direction: Direction;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function FlightDetailSheet({
  flight,
  direction,
  open,
  onOpenChange,
}: FlightDetailSheetProps) {
  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        closeLabel="閉じる"
        className="max-h-[90vh] overflow-y-auto rounded-t-2xl"
      >
        {flight ? (
          <>
            <SheetHeader className="text-left">
              <SheetTitle className="flex items-center gap-2 text-xl">
                <IconPlane className="h-5 w-5 text-muted-foreground" aria-hidden />
                <span className="font-bold tracking-wide">{flight.flightNo}</span>
                <span className="text-sm font-normal text-muted-foreground">
                  {flight.airlineLabel}
                </span>
              </SheetTitle>
              <SheetDescription className="flex items-center gap-2">
                <span>
                  {flight.origin.code} → {flight.destination.code}
                </span>
                <span aria-hidden>·</span>
                <StatusBadge status={flight.status} />
              </SheetDescription>
            </SheetHeader>

            <div className="mt-4 space-y-5 pb-2">
              {/* 欠航 / 遅延の理由 */}
              {flight.status === "cancelled" ? (
                <Alert variant="destructive">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden />
                  <AlertTitle>この便は欠航となりました</AlertTitle>
                  <AlertDescription>
                    {flight.delayReason ?? "運航上の都合により欠航となりました。"}
                    ご予約のお客様は便の振替についてご案内いたします。
                  </AlertDescription>
                </Alert>
              ) : flight.status === "delayed" && flight.delayReason ? (
                <Alert variant="warning">
                  <IconAlertTriangle className="h-4 w-4" aria-hidden />
                  <AlertTitle>
                    遅延しています
                    {flight.estimated ? `（${direction === "departure" ? "出発見込" : "到着見込"} ${flight.estimated}）` : ""}
                  </AlertTitle>
                  <AlertDescription>遅延の理由：{flight.delayReason}</AlertDescription>
                </Alert>
              ) : null}

              {/* 区間（出発→到着）と予実時刻 */}
              <section aria-labelledby="leg-heading">
                <h3
                  id="leg-heading"
                  className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
                >
                  区間
                </h3>
                <RouteStops
                  stops={legStops(flight)}
                  timeLabels={{
                    planned: direction === "departure" ? "定刻(STD)" : "定刻(STA)",
                    actual: direction === "departure" ? "出発見込" : "到着見込",
                  }}
                  statusLabels={{
                    pending: STATUS_LABEL.ontime,
                    current: "搭乗中",
                    completed: direction === "departure" ? "出発済" : "到着済",
                    delayed: "遅延",
                    failed: "欠航",
                  }}
                />
              </section>

              {/* 便の詳細情報 */}
              <section aria-labelledby="info-heading">
                <h3
                  id="info-heading"
                  className="mb-2 text-xs font-semibold uppercase tracking-wide text-muted-foreground"
                >
                  便の情報
                </h3>
                <MetadataList items={detailItems(flight, direction)} />
              </section>
            </div>
          </>
        ) : null}
      </SheetContent>
    </Sheet>
  );
}

"use client";

import * as React from "react";
import { IconStarFilled } from "@tabler/icons-react";
import { Badge, ListCard } from "@gunjo/ui";
import type { Direction, Flight } from "./data";
import { STATUS_SEVERITY, StatusBadge } from "./status-ui";

export interface FlightRowProps {
  flight: Flight;
  direction: Direction;
  /** マイフライトとしてピン留めされているか */
  pinned?: boolean;
  selected?: boolean;
  onSelect: (flight: Flight) => void;
}

/** 出発便/到着便の1便を表すタップ可能な行（一覧の最重要要素） */
export function FlightRow({
  flight,
  direction,
  pinned = false,
  selected = false,
  onSelect,
}: FlightRowProps) {
  const isDeparture = direction === "departure";
  const counterport = isDeparture ? flight.destination : flight.origin;
  const counterLabel = isDeparture ? "行き" : "発";

  // 定刻 / 変更時刻 を leading に大きく表示
  const showEstimated = !!flight.estimated && flight.status !== "ontime";

  const gateLabel = isDeparture
    ? flight.gate
      ? `${flight.gate}番ゲート`
      : null
    : flight.spot
      ? `${flight.spot}番スポット`
      : null;

  return (
    <ListCard
      severity={STATUS_SEVERITY[flight.status]}
      selected={selected}
      onSelect={() => onSelect(flight)}
      aria-label={`${flight.flightNo} ${counterport.name}${counterLabel} ${flight.scheduled}${
        showEstimated ? ` 変更 ${flight.estimated}` : ""
      } の便の詳細を開く`}
      leading={
        <div className="flex w-[68px] flex-col items-start tabular-nums">
          <span
            className={
              "text-lg font-bold leading-tight" +
              (showEstimated || flight.status === "cancelled"
                ? " text-muted-foreground line-through decoration-1"
                : "")
            }
          >
            {flight.scheduled}
          </span>
          {showEstimated ? (
            <span className="text-lg font-bold leading-tight text-warning">
              {flight.estimated}
            </span>
          ) : null}
        </div>
      }
      title={
        <span className="flex items-center gap-2">
          {pinned ? (
            <IconStarFilled
              className="h-4 w-4 text-warning"
              aria-label="マイフライト"
            />
          ) : null}
          <span className="font-bold tracking-wide">{flight.flightNo}</span>
          <span className="text-xs font-normal text-muted-foreground">
            {flight.airlineLabel}
          </span>
        </span>
      }
      description={
        <span>
          {counterport.name}
          <span className="text-muted-foreground">（{counterport.code}）</span>
          {counterLabel}
        </span>
      }
      status={<StatusBadge status={flight.status} />}
      meta={
        gateLabel ? (
          <span className="inline-flex items-center gap-1.5">
            <span className="tabular-nums">{gateLabel}</span>
            {isDeparture && flight.gateChanged ? (
              <Badge variant="warning" className="text-[10px]">
                変更
              </Badge>
            ) : null}
          </span>
        ) : null
      }
    />
  );
}

import * as React from "react";
import {
  IconAlertTriangle,
  IconBan,
  IconCheck,
  IconClock,
  IconDoorEnter,
  IconPlaneArrival,
  IconPlaneDeparture,
} from "@tabler/icons-react";
import { Badge } from "@gunjo/ui";
import type { ListCardSeverity } from "@gunjo/ui";
import type { Direction, FlightStatus } from "./data";
import { STATUS_LABEL } from "./data";

// Badge の variant プロップの型を Badge 自身から引く
// （barrel が BadgeVariantKey を再エクスポートしていないため）
type BadgeVariant = React.ComponentProps<typeof Badge>["variant"];

/** 運航状態 → Badge の見た目 */
const STATUS_BADGE: Record<FlightStatus, BadgeVariant> = {
  ontime: "success",
  delayed: "warning",
  cancelled: "destructive",
  checkin: "info",
  boarding: "info",
  departed: "secondary",
  arrived: "secondary",
};

/** 運航状態 → ListCard の左ボーダー severity（一覧で乱れを目立たせる） */
export const STATUS_SEVERITY: Record<FlightStatus, ListCardSeverity> = {
  ontime: "neutral",
  delayed: "warning",
  cancelled: "critical",
  checkin: "info",
  boarding: "info",
  departed: "neutral",
  arrived: "neutral",
};

const STATUS_ICON: Record<FlightStatus, React.ComponentType<{ className?: string }>> = {
  ontime: IconCheck,
  delayed: IconClock,
  cancelled: IconBan,
  checkin: IconDoorEnter,
  boarding: IconDoorEnter,
  departed: IconPlaneDeparture,
  arrived: IconPlaneArrival,
};

/** 一覧・詳細で使う運航状態バッジ */
export function StatusBadge({ status }: { status: FlightStatus }) {
  const Icon = STATUS_ICON[status];
  return (
    <Badge variant={STATUS_BADGE[status]} icon={<Icon className="h-3.5 w-3.5" />}>
      {STATUS_LABEL[status]}
    </Badge>
  );
}

/** 方向に応じた便アイコン（出発便 / 到着便） */
export function DirectionIcon({
  direction,
  className,
}: {
  direction: Direction;
  className?: string;
}) {
  return direction === "departure" ? (
    <IconPlaneDeparture className={className} aria-hidden />
  ) : (
    <IconPlaneArrival className={className} aria-hidden />
  );
}

export { IconAlertTriangle };
